// src/store/slices/categoriesSlice.js

import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { BASE_URL } from '../../utils/api'; // Импорт базового URL

// 1. Асинхронный Thunk для запроса данных
export const fetchCategories = createAsyncThunk(
  'categories/fetchCategories',
  async (_, { rejectWithValue }) => {
    try {
      const response = await fetch(`${BASE_URL}/categories/all`);

      if (!response.ok) {
        // Если ответ не 200-299, бросаем ошибку, которая попадет в rejectWithValue
        throw new Error('Server Error!');
      }

      const data = await response.json();
      return data;

    } catch (error) {
      // Возвращаем ошибку с помощью rejectWithValue
      return rejectWithValue(error.message);
    }
  }
);

// 2. Инициализация состояния
const initialState = {
  list: [],
  status: 'idle', // 'idle' | 'loading' | 'succeeded' | 'failed'
  error: null,
};

// 3. Создание Слайса
const categoriesSlice = createSlice({
  name: 'categories',
  initialState,
  reducers: {
    // Здесь могут быть синхронные редьюсеры, но для категорий они не нужны
  },
  extraReducers: (builder) => {
    builder
      // Состояние: Загрузка началась
      .addCase(fetchCategories.pending, (state) => {
        state.status = 'loading';
        state.error = null;
      })
      // Состояние: Загрузка успешна
      .addCase(fetchCategories.fulfilled, (state, action) => {
        state.status = 'succeeded';
        state.list = action.payload; // Записываем полученные категории
      })
      // Состояние: Загрузка провалена
      .addCase(fetchCategories.rejected, (state, action) => {
        state.status = 'failed';
        state.error = action.payload; // Записываем ошибку
      });
  },
});

export default categoriesSlice.reducer;
